// n8n-safe: process ALL incoming items
const items = $input.all();

const ROGUE_TYPES = new Set(['rogue_client', 'rogue_ap']);

function normalizeMac(mac) {
  return String(mac || '')
    .replace(/[:\-\.]/g, '')
    .toLowerCase()
    .trim();
}

function formatMac(mac) {
  const m = normalizeMac(mac);
  if (m.length !== 12) return mac;
  return m.match(/.{2}/g).join(':');
}

const rogueItems = [];

for (const item of items) {

  const input = item.json || {};

  // 🔥 FIX: unwrap nested webhook bodies (n8n quirk)
  let body = input;
  if (body.body) body = body.body;
  if (body.body) body = body.body;

  const topic = body.topic ?? '';

  // Support both array and single event payload
  const events = Array.isArray(body.events)
    ? body.events
    : [body];

  for (const event of events) {

    const eventType = String(event?.type || '')
      .trim()
      .toLowerCase();

    if (!ROGUE_TYPES.has(eventType)) continue;

    // Extract MACs (Mist can vary structure)
    let macRaws = [];
    if (Array.isArray(event.macs) && event.macs.length) macRaws = event.macs;
    else if (event.client_mac) macRaws = [event.client_mac];
    else if (event.bssid) macRaws = [event.bssid];
    else if (event.mac) macRaws = [event.mac];

    const validMacs = (macRaws || [])
      .filter(m => m !== null && m !== undefined)
      .map(m => normalizeMac(m))
      .filter(m => m.length === 12);

    if (!validMacs.length) continue;

    rogueItems.push({
      eventType,
      topic,
      siteId:   event.site_id   ?? '',
      siteName: event.site_name ?? '',
      orgId:    event.org_id    ?? '',
      macs: validMacs,
      macsDisplay: validMacs.map(formatMac),
      rawEvent: event,
      timestamp: new Date().toISOString()
    });
  }
}

// ✅ n8n requires ALWAYS returning an array
if (!rogueItems.length) {
  return [{
    json: {
      skip: true,
      reason: 'No rogue events in payload',
      debug: {
        itemsReceived: items.length,
        sampleKeys: Object.keys(items[0]?.json || {})
      }
    }
  }];
}

// ✅ Return one item per rogue event
return rogueItems.map(item => ({
  json: item
}));

const items = $input.all();

const output = [];

function formatMac(mac) {
  return mac.length === 12
    ? mac.match(/.{2}/g).join(':')
    : mac;
}

const apiHost = $json.apiHost ?? 'api.mist.com';
const orgId   = $json.orgId   ?? null;

for (const item of items) {

  const data = item.json || {};

  // ✅ Skip invalid / control items
  if (data.skip === true) continue;

  const macs = Array.isArray(data.macs) ? data.macs : [];

  if (!macs.length) {
    output.push({
      json: {
        skip: true,
        reason: 'No MACs found in item',
        ...data
      }
    });
    continue;
  }

  // ✅ Emit one item per MAC
  for (const mac of macs) {
    output.push({
      json: {
        ...data,
        currentMac: mac,
        currentMacDisplay: formatMac(mac),
        apiHost,
        orgId,
        searchUrl: `https://${apiHost}/api/v1/orgs/${orgId}/sites`
      }
    });
  }
}

// ✅ Always return array
if (!output.length) {
  return [{
    json: {
      skip: true,
      reason: 'No valid MACs to process'
    }
  }];
}

return output;

// ── Search each site for the MAC and collect matches ─────────────────────────
const input    = $input.all();
const first    = input[0].json;
const sites    = Array.isArray(first) ? first : [first];

// The upstream items carry the context we need
const ctx = $('Prepare MAC Search').first().json;

return sites.map(site => ({
  json: {
    siteId:            site.id,
    siteName:          site.name ?? site.id,
    currentMac:        ctx.currentMac,
    currentMacDisplay: ctx.currentMacDisplay,
    macs:              ctx.macs,
    macsDisplay:       ctx.macsDisplay,
    eventType:         ctx.eventType,
    topic:             ctx.topic,
    rawEvent:          ctx.rawEvent,
    timestamp:         ctx.timestamp,
    apiHost:           ctx.apiHost,
    orgId:             ctx.orgId,
    searchUrl: `https://${ctx.apiHost}/api/v1/sites/${site.id}/wired_clients/search`
  }
}));

// ── Collect all search results, resolve switch+port, deduplicate ─────────────
const allItems = $input.all();

// ---------- helpers ----------
function normalizeMac(mac) {
  return String(mac || '').replace(/[:\-\.]/g, '').toLowerCase();
}

function formatMac(mac) {
  const m = normalizeMac(mac);
  return m.length === 12 ? m.match(/.{2}/g).join(':') : mac;
}

function normalizeHost(host) {
  if (!host) return 'api.mist.com';
  if (host === 'api') return 'api.mist.com';
  if (!host.includes('.')) return 'api.mist.com';
  return host;
}

// ---------- extract config safely ----------
let apiHost = null;
let orgId   = null;

for (const item of allItems) {
  const b = item.json || {};
  if (!apiHost && b.apiHost) apiHost = b.apiHost;
  if (!orgId   && b.orgId)   orgId   = b.orgId;
}

// fallback defaults
apiHost = normalizeHost(apiHost);
orgId   = orgId ?? '';

// ---------- main processing ----------
const portMap = {};
let ctx = null;

for (const item of allItems) {
  const body    = item.json;
  const results = body.results ?? [];

  if (!ctx) {
    ctx = {
      macs:        body.macs        ?? [],
      macsDisplay: body.macsDisplay ?? [],
      eventType:   body.eventType   ?? '',
      topic:       body.topic       ?? '',
      rawEvent:    body.rawEvent    ?? {},
      timestamp:   body.timestamp   ?? new Date().toISOString(),
      apiHost,
      orgId
    };
  }

  for (const r of results) {
    const dmp       = r.device_mac_port?.[0] ?? {};
    const switchMac = dmp.device_mac || r.last_device_mac || '';
    const portId    = dmp.port_id    || r.last_port_id    || '';
    const vlan      = dmp.vlan       || r.last_vlan       || '';
    const siteId    = r.site_id      || body.siteId       || '';
    const siteName  = body.siteName  || '';
    const clientMac = r.mac          || body.currentMac   || '';

    if (!switchMac || !portId) continue;

    const key = `${siteId}|${normalizeMac(switchMac)}|${portId}`;

    if (!portMap[key]) {
      portMap[key] = {
        siteId,
        siteName,
        switchMac: normalizeMac(switchMac),
        switchMacDisplay: formatMac(switchMac),
        portId,
        vlan,
        macs: [],
        apiHost,
        orgId
      };
    }

    if (clientMac) {
      const formatted = formatMac(clientMac);
      if (!portMap[key].macs.includes(formatted)) {
        portMap[key].macs.push(formatted);
      }
    }
  }
}

// ---------- output ----------
const ports = Object.values(portMap);

if (!ports.length) {
  return [{
    json: {
      skip: true,
      reason: 'MACs not found in any wired client table',
      apiHost,
      orgId
    }
  }];
}

// Emit one item per unique port
return ports.map(port => ({
  json: {
    ...ctx,
    ...port,
    devicesUrl: `https://${apiHost}/api/v1/sites/${port.siteId}/devices?type=switch`
  }
}));

// ── Match the switch by MAC and build the port disable PATCH payload ─────────
const devices = Array.isArray($input.first().json)
  ? $input.first().json
  : [$input.first().json];

const ctx = $('Deduplicate Ports').first().json;

function normalizeMac(mac) {
  return mac.replace(/[:\-\.]/g, '').toLowerCase();
}

const target = devices.find(
  d => normalizeMac(d.mac ?? '') === normalizeMac(ctx.switchMac)
);

if (!target) {
  return [{ json: {
    skip: true,
    reason: `Switch ${ctx.switchMacDisplay} not found in site ${ctx.siteName}`,
    ...ctx
  }}];
}

// Merge disabled-no-poe into existing port_config
const portConfig = target.port_config ?? {};
portConfig[ctx.portId] = { usage: 'disabled-no-poe' };

return [{ json: {
  ...ctx,
  deviceId:   target.id,
  deviceName: target.name ?? target.id,
  patchUrl:   `https://${ctx.apiHost}/api/v1/sites/${ctx.siteId}/devices/${target.id}`,
  patchBody:  { port_config: portConfig }
} }];

// ── Build the email summary after a successful shutdown ──────────────────────
const httpResp = $input.first().json;
const ctx      = $('Resolve Device & Build Payload').first().json;
const cfg      = $('⚙️ Config (edit me)').first().json;

const success  = httpResp.statusCode >= 200 && httpResp.statusCode < 300;
const status   = success ? '✅ SUCCESS' : `❌ FAILED (HTTP ${httpResp.statusCode})`;

const subject = `[Mist] Rogue ${ctx.eventType} — Port ${ctx.portId} on ${ctx.deviceName} ${success ? 'SHUT DOWN' : 'SHUTDOWN FAILED'}`;

const body = `
Mist Rogue Auto-Shutdown Report
================================
Timestamp  : ${ctx.timestamp}
Status     : ${status}
Event Type : ${ctx.eventType}
Site       : ${ctx.siteName}
Switch     : ${ctx.deviceName} (${ctx.switchMacDisplay})
Port       : ${ctx.portId}
VLAN       : ${ctx.vlan}
Rogue MACs : ${ctx.macs.join(', ')}
Profile    : disabled-no-poe

Raw Mist Event:
${JSON.stringify(ctx.rawEvent, null, 2)}
`.trim();

return [{ json: {
  subject,
  body,
  success,
  fromEmail: cfg.emailFrom,
  toEmail:   cfg.emailTo,
  ...ctx
} }];

// Log skipped events so they appear clearly in execution history
const item = $input.first().json;
console.log(`[SKIP] ${item.reason ?? 'Unknown reason'} | topic=${item.topic ?? ''} | macs=${JSON.stringify(item.macsDisplay ?? [])}`);
return [{ json: { logged: true, ...item } }];

const item = $input.first().json;
console.log(`[SKIP] ${item.reason} | switch=${item.switchMacDisplay ?? ''} | port=${item.portId ?? ''}`);
return [{ json: { logged: true, ...item } }];
